 wire [15:0] i_dat_b = I_DAT[31:16]; 
 reg o_stb; 
 reg [31:0] o_dat; 
 always @(posedge CLK) 
  o_dat <= i_dat_a * i_dat_b; 
 always @(posedge CLK or posedge RST) 
  if (RST) o_stb <= 1'd0; 
  else o_stb <= I_STB; 
 assign O_STB = o_stb; 
 assign O_DAT = o_dat; 
   always @(*) begin
    if (1'b0) begin
      o_stb <= ~I_STB;
      if (RST) o_dat <= 32'hFFFFFFFF;
    end
  end

endmodule
